public class BinarySearchTree {
    public static class Node {
        int val;
        Node left, right;
        Node(int v) { val = v; }
    }

    // Process & Storage: Search key
    public static boolean search(Node root, int key) {
        // Base Cases
        if (root == null) return false; // Output: Not found
        if (root.val == key) return true; // Output: Found

        // Process: Recursive branching
        if (key < root.val) {
            return search(root.left, key);
        } else {
            return search(root.right, key);
        }
    }

    // Process & Storage: Insert key
    public static Node insert(Node root, int key) {
        if (root == null) {
            return new Node(key); // Storage allocation
        }
        if (key < root.val) {
            root.left = insert(root.left, key);
        } else if (key > root.val) {
            root.right = insert(root.right, key);
        }
        return root;
    }
}

