public class BSTMinVal {
    public static int findMin(BinarySearchTree.Node root) {
        // Input: root pointer
        if (root == null) return -1;

        BinarySearchTree.Node current = root; // Storage

        // Process: Keep sliding left
        while (current.left != null) {
            current = current.left;
        }

        // Output: leftmost value
        return current.val;
    }
}

