public class BSTChecker {
    public static boolean isBST(BinarySearchTree.Node root) {
        // Input: root node
        return validate(root, Long.MIN_VALUE, Long.MAX_VALUE);
    }

    private static boolean validate(BinarySearchTree.Node node, long min, long max) {
        // Process: Base check
        if (node == null) return true; // Output: base

        // Process: Range check
        if (node.val <= min || node.val >= max) {
            return false; // Output: invalid
        }

        // Process: Recurse left and right boundaries
        return validate(node.left, min, node.val) && 
               validate(node.right, node.val, max); // Output
    }
}

public class SecondLargestBST {
    private static class Counter {
        int count = 0; // Storage
        int result = -1; // Storage
    }

    public static int findSecondLargest(BinarySearchTree.Node root) {
        // Input: root pointer
        Counter c = new Counter(); // Storage
        reverseInorder(root, c);
        return c.result; // Output
    }

    private static void reverseInorder(BinarySearchTree.Node node, Counter c) {
        if (node == null || c.count >= 2) return;

        // Process: visit right first (largest values)
        reverseInorder(node.right, c);

        c.count++;
        if (c.count == 2) {
            c.result = node.val; // Storage update
            return;
        }

        // Process: visit left
        reverseInorder(node.left, c);
    }
}

import java.util.ArrayList;

public class BSTEquality {
    public static boolean areEqual(BinarySearchTree.Node root1, BinarySearchTree.Node root2) {
        // Input: two BST roots
        ArrayList<Integer> list1 = new ArrayList<>(); // Storage
        ArrayList<Integer> list2 = new ArrayList<>(); // Storage

        // Process: get sorted lists
        inorder(root1, list1);
        inorder(root2, list2);

        // Output: check equality
        return list1.equals(list2);
    }

    private static void inorder(BinarySearchTree.Node node, ArrayList<Integer> list) {
        if (node == null) return;
        inorder(node.left, list);
        list.add(node.val);
        inorder(node.right, list);
    }
}

public class KthLargestBST {
    static int count = 0;   // Storage: nodes visited so far
    static int result = -1; // Storage: holds the answer

    public static int kthLargest(BinarySearchTree.Node root, int k) {
        // Input: BST root and rank k (from the largest)
        count = 0;
        result = -1;
        reverseInorder(root, k);
        return result; // Output: the k-th largest value
    }

    private static void reverseInorder(BinarySearchTree.Node node, int k) {
        if (node == null || count >= k) return; // prune once found
        // Process: visit RIGHT subtree first (largest values)
        reverseInorder(node.right, k);
        count++;
        if (count == k) {            // Process: k-th node reached
            result = node.val;
            return;
        }
        reverseInorder(node.left, k);
    }
}
